func splitCommand(raw string) (string, []string) {
	raw = strings.TrimSpace(raw)
	if raw == "" {
		return "", nil
	}
	parts := fieldsQuoted(raw)
	if len(parts) == 0 {
		return "", nil
	}
	return parts[0], parts[1:]
}

func fieldsQuoted(s string) []string {
	var out []string
	var b strings.Builder
	inQuote := false
	escape := false
	flush := func() {
		if b.Len() > 0 {
			out = append(out, b.String())
			b.Reset()
		}
	}
	for _, r := range s {
		if escape {
			b.WriteRune(r)
			escape = false
			continue
		}
		switch r {
		case '\\':
			escape = true
		case '"':
			inQuote = !inQuote
		case ' ', '\t', '\r', '\n':
			if inQuote {
				b.WriteRune(r)
			} else {
				flush()
			}
		default:
			b.WriteRune(r)
		}
	}
	flush()
	return out
}

func parseHeaderLine(line string) map[string]string {
	m := make(map[string]string)
	line = strings.TrimSpace(line)
	if line == "" {
		return m
	}
	if strings.HasPrefix(strings.ToUpper(line), "CONNECT ") {
		line = strings.TrimSpace(line[len("CONNECT "):])
	}
	parts := strings.Split(line, ";")
	for _, p := range parts {
		p = strings.TrimSpace(p)
		if p == "" {
			continue
		}
		kv := strings.SplitN(p, "=", 2)
		if len(kv) != 2 {
			continue
		}
		k := strings.ToLower(strings.TrimSpace(kv[0]))
		v := strings.TrimSpace(kv[1])
		v = strings.Trim(v, `"`)
		m[k] = v
	}
	return m
}

func parseRole(s string) Role {
	switch strings.ToLower(strings.TrimSpace(s)) {
	case "admin":
		return RoleAdmin
	case "mod", "moderator":
		return RoleMod
	default:
		return RolePlayer
	}
}

func sanitizeName(s string) string {
	s = strings.TrimSpace(s)
	if s == "" {
		return ""
	}
	if len(s) > 24 {
		s = s[:24]
	}
	var b strings.Builder
	for _, r := range s {
		if (r >= 'a' && r <= 'z') || (r >= 'A' && r <= 'Z') || (r >= '0' && r <= '9') || r == '_' || r == '-' {
			b.WriteRune(r)
		}
	}
	out := b.String()
	if out == "" {
		return ""
	}
	return out
}

func remoteIP(addr string) string {
	host, _, err := net.SplitHostPort(addr)
	if err != nil {
		return addr
	}
	return host
}

func writeJSONLine(rw *bufio.ReadWriter, env Envelope) error {
	b, err := json.Marshal(env)
	if err != nil {
		return err
	}
	if _, err := rw.Write(b); err != nil {
		return err
	}
	if err := rw.WriteByte('\n'); err != nil {
		return err
	}
	return nil
}

func mustJSON(v any) json.RawMessage {
	b, _ := json.Marshal(v)
	return b
}

func newID() string {
	var b [16]byte
	_, _ = rand.Read(b[:])
	return hex.EncodeToString(b[:])
}

func getenv(k, def string) string {
	if v := os.Getenv(k); v != "" {
		return v
	}
	return def
}

